function SandboxPage(){const runs=[{id:"SB-001",repo:"thefold-api",mode:"docker",status:"pass",steps:[{n:"typecheck",s:"pass",d:"tsc --noEmit",t:"2.1s"},{n:"lint",s:"pass",d:"eslint --no-error-on-unmatched-pattern",t:"1.4s"},{n:"test",s:"pass",d:"12/12 tests passed",t:"4.8s"},{n:"snapshot",s:"pass",d:"3 files changed",t:"0.2s"},{n:"performance",s:"pass",d:"Build: 1.2s, 42 files",t:"1.3s"}],time:"14m",task:"T-001"},{id:"SB-002",repo:"thefold-frontend",mode:"docker",status:"warn",steps:[{n:"typecheck",s:"pass",d:"tsc --noEmit",t:"3.2s"},{n:"lint",s:"warn",d:"2 warnings",t:"1.8s"},{n:"test",s:"pass",d:"8/8 tests",t:"3.1s"},{n:"snapshot",s:"pass",d:"1 file changed",t:"0.1s"},{n:"performance",s:"pass",d:"Build: 2.4s, 67 files",t:"2.1s"}],time:"1t",task:"T-002"},{id:"SB-003",repo:"thefold-api",mode:"filesystem",status:"fail",steps:[{n:"typecheck",s:"fail",d:"TS2345: Argument type mismatch",t:"1.9s"},{n:"lint",s:"pass",d:"0 warnings",t:"1.2s"},{n:"test",s:"fail",d:"2/12 failed",t:"5.4s"},{n:"snapshot",s:"disabled",d:"Feature flag off"},{n:"performance",s:"disabled",d:"Feature flag off"}],time:"3t",task:"T-003"}];
const[sel,setSel]=useState(null);const sb=sel!==null?runs.find(r=>r.id===sel):null;
return(<><div style={{paddingTop:40,paddingBottom:24}}><h2 style={{fontSize:28,fontWeight:600,color:T.text,letterSpacing:"-0.03em",fontFamily:T.brandFont,marginBottom:8}}>Sandbox</h2><p style={{fontSize:13,color:T.textMuted}}>Isolert kodevalidering — typecheck, lint, test, snapshot, performance.</p></div>
<GR><div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr 1fr",border:`1px solid ${T.border}`,borderRadius:T.r,position:"relative",overflow:"hidden"}}><PC/>{[{l:"KJØRINGER",v:runs.length},{l:"BESTÅTT",v:runs.filter(r=>r.status==="pass").length,c:T.success},{l:"ADVARSLER",v:runs.filter(r=>r.status==="warn").length,c:T.warning},{l:"FEILET",v:runs.filter(r=>r.status==="fail").length,c:T.error}].map((s,i)=>(<div key={i} style={{padding:"18px 20px",borderRight:i<3?`1px solid ${T.border}`:"none"}}><div style={{fontSize:10,fontWeight:500,color:T.textMuted,textTransform:"uppercase",letterSpacing:"0.06em",marginBottom:6}}>{s.l}</div><div style={{fontSize:28,fontWeight:600,color:s.c||T.text,letterSpacing:"-0.03em",lineHeight:1}}>{s.v}</div></div>))}</div></GR>
<GR mb={40}><div style={{display:"grid",gridTemplateColumns:sb?"1fr 1fr":"1fr",border:`1px solid ${T.border}`,borderTop:"none",borderRadius:`0 0 ${T.r}px ${T.r}px`,minHeight:300,position:"relative",overflow:"hidden"}}><PC/><div style={{borderRight:sb?`1px solid ${T.border}`:"none"}}>{runs.map((r,i)=>(<div key={r.id} onClick={()=>setSel(r.id===sel?null:r.id)} style={{padding:"14px 20px",cursor:"pointer",background:sel===r.id?T.subtle:"transparent",borderBottom:i<runs.length-1?`1px solid ${T.border}`:"none",borderLeft:sel===r.id?`3px solid ${T.accent}`:"3px solid transparent"}}><div style={{display:"flex",alignItems:"center",gap:10,marginBottom:4}}><span style={{fontSize:10,fontFamily:T.mono,color:T.textFaint}}>{r.id}</span><span style={{fontSize:13,fontWeight:500,color:T.text}}>{r.repo}</span><Tag variant={r.status==="pass"?"success":r.status==="warn"?"accent":"error"}>{r.status}</Tag><Tag>{r.mode}</Tag></div><div style={{display:"flex",gap:12}}><span style={{fontSize:10,fontFamily:T.mono,color:T.textFaint}}>task: {r.task}</span><span style={{fontSize:10,color:T.textFaint,marginLeft:"auto"}}>{r.time}</span></div></div>))}</div>
{sb&&<div style={{padding:24}}><div style={{fontSize:16,fontWeight:600,color:T.text,fontFamily:T.brandFont,marginBottom:4}}>{sb.repo}</div><div style={{display:"flex",gap:8,marginBottom:16}}><Tag variant={sb.status==="pass"?"success":sb.status==="warn"?"accent":"error"}>{sb.status}</Tag><Tag>{sb.mode}</Tag></div><SL>VALIDATION PIPELINE</SL>{sb.steps.map((st,i)=>(<div key={i} style={{display:"flex",alignItems:"center",gap:10,padding:"10px 0",borderBottom:i<sb.steps.length-1?`1px solid ${T.border}`:"none"}}><div style={{width:8,height:8,borderRadius:"50%",background:st.s==="pass"?T.success:st.s==="warn"?T.warning:st.s==="fail"?T.error:T.textFaint}}/><span style={{fontSize:13,fontWeight:500,color:T.text,width:100}}>{st.n}</span><span style={{fontSize:12,color:T.textMuted,flex:1}}>{st.d}</span>{st.t&&<span style={{fontSize:10,fontFamily:T.mono,color:T.textFaint}}>{st.t}</span>}</div>))}</div>}</div></GR></>);}

