{[{l:"API-nøkkel",v:"thf_••••••••k7x2",a:"Vis"},{l:"Webhook-secret",v:"whsec_••••••••m3p1",a:"Regenerer"},{l:"HMAC-algoritme",v:"SHA-256"},{l:"Rate limit",v:"100 req/min"}].map((f,i)=>(<div key={i} style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"10px 0",borderBottom:i<3?`1px solid ${T.border}`:"none"}}><span style={{fontSize:12,color:T.textMuted}}>{f.l}</span><div style={{display:"flex",alignItems:"center",gap:8}}><span style={{fontSize:12,fontFamily:T.mono,color:T.textSec}}>{f.v}</span>{f.a&&<Btn sm>{f.a}</Btn>}</div></div>))}
